// n8n webhook com responseMode=responseNode passa o request completo
// O payload real do Z-API está em .body; fallback para raiz se já vier desempacotado
const raw = $input.first().json;
const body = raw.body || raw;

// Ignora mensagens de grupos (bot é para atendimento individual)
if (body.isGroup === true) {
  return [];
}

// Ignora mensagens do próprio bot
if (body.fromMe === true || body.fromMe === 'true') {
  return [];
}

// Ignora eventos que não são mensagens recebidas
if (body.type && body.type !== 'ReceivedCallback') {
  return [];
}

// Para DMs: participantPhone é o remetente real; phone é o chatId (igual ao remetente em DMs)
const rawPhone = body.participantPhone
  || body.phone
  || body.from
  || body.chatId
  || body.sender
  || (body.key && body.key.remoteJid)
  || '';

let phone = String(rawPhone)
  .replace('@c.us', '')
  .replace('@s.whatsapp.net', '')
  .replace('@g.us', '')
  .replace('@lid', '')
  .replace('+', '')
  .trim();

// Normaliza números brasileiros: garante o 9 dígito após DDD (55 + 2 dígitos DDD + 9 + 8 dígitos)
// Ex: 551187654321 (sem 9) → 5511987654321 (com 9)
if (/^55\d{10}$/.test(phone)) {
  // 55 + DDD (2) + número (8) = 12 dígitos → adiciona 9 após DDD
  phone = '55' + phone.slice(2, 4) + '9' + phone.slice(4);
}

const messageText = String(body.text?.message || body.body || body.message || '');
const messageType = String(body.type || 'ReceivedCallback');
const timestamp = new Date().toISOString();

if (!phone || !messageText.trim()) {
  return [];
}

return [{
  json: {
    phone,
    messageText: messageText.trim(),
    messageTextLower: messageText.trim().toLowerCase(),
    messageType,
    timestamp
  }
}];

// Armazena sessões em Static Data do N8N (sem Redis!)
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const data = $input.first().json;

// Modo debug: apenas passa os dados para frente sem salvar sessão
if (data._debugMode) {
  return [{ json: data }];
}

const phone = data.phone;
const messageData = data;

let session = staticData.sessions[phone] || null;
const isNew = !session;

if (!session) {
  session = {
    phone,
    step: 'INICIO',
    cartItems: [],
    customerName: '',
    currentCategory: null,
    selectedProduct: null,
    pendingProduct: null,
    deliveryAddress: '',
    paymentMethod: '',
    orderTotal: 0,
    orderId: null,
    orderStatus: null,
    messageCount: 0,
    startedAt: messageData.timestamp,
    lastInteraction: messageData.timestamp
  };
}

session.lastInteraction = messageData.timestamp;
session.messageCount = (session.messageCount || 0) + 1;

// Salva de volta
staticData.sessions[phone] = session;

// Limpa sessões antigas (+2h sem interação) para não acumular
const now = new Date();
Object.keys(staticData.sessions).forEach(p => {
  const s = staticData.sessions[p];
  const diff = (now - new Date(s.lastInteraction)) / 1000 / 60;
  if (diff > 120) delete staticData.sessions[p];
});

return [{
  json: {
    ...messageData,
    session,
    isNewSession: isNew
  }
}];

// Roteamento baseado no estado da sessão e conteúdo da mensagem
const data = $input.first().json;

// Modo debug: pula toda lógica de rota
if (data._debugMode) {
  return [{ json: { ...data, route: 'debug_only' } }];
}

const session = data.session;
const msg = data.messageTextLower;

// Palavras-chave para falar com humano (qualquer etapa)
const wantsHuman = msg.includes('humano') || msg.includes('atendente') || msg.includes('pessoa') || msg.includes('falar com alguem') || msg.includes('ajuda humana');

// Palavras-chave para resetar/voltar ao início
const wantsReset = msg === 'menu' || msg === 'inicio' || msg === 'início' || msg === 'voltar' || msg === '0';

let route = 'bot_logic'; // padrão

// menu sempre sai da fila humana; nos demais estados, respeita exceções do fluxo
if (wantsReset && (
  session.step === 'AGUARDANDO_HUMANO' ||
  (session.step !== 'INICIO' && session.step !== 'AGUARDANDO_NOME' && session.step !== 'DETALHES_PRODUTO' && session.step !== 'ESCOLHENDO_PRODUTO' && session.step !== 'ESCOLHENDO_CATEGORIA')
)) {
  route = 'reset_menu';
} else if (session.step === 'AGUARDANDO_HUMANO') {
  route = 'em_fila_humano';
} else if (wantsHuman) {
  route = 'transferir_humano';
} else {
  route = 'bot_logic';
}

return [{ json: { ...data, route } }];

// Lógica completa do bot - catálogo, carrinho e pedido
const staticData = $getWorkflowStaticData('global');
const data = $input.first().json;
const msg = data.messageTextLower;
const msgOriginal = data.messageText;
let session = { ...data.session };
let responseText = '';
let useAI = false;
let aiContext = '';

// =============================================
// CATÁLOGO DE PRODUTOS
// =============================================
const CATALOGO = {
  categorias: [
    { id: '1', nome: 'Analgésicos e Antitérmicos', emoji: '💊' },
    { id: '2', nome: 'Antibióticos (receita obrigatória)', emoji: '💉' },
    { id: '3', nome: 'Vitaminas e Suplementos', emoji: '🌿' },
    { id: '4', nome: 'Dermatológicos', emoji: '🧴' },
    { id: '5', nome: 'Cardiovascular (receita obrigatória)', emoji: '❤️‍🩹' },
    { id: '6', nome: 'Gastrintestinal', emoji: '🫁' }
  ],
  produtos: [
    { id: 'P01', cat: '1', nome: 'Dipirona 500mg', desc: 'Caixa c/ 20 comprimidos', preco: 8.90, receita: false, estoque: true },
    { id: 'P02', cat: '1', nome: 'Paracetamol 750mg', desc: 'Caixa c/ 20 comprimidos', preco: 6.50, receita: false, estoque: true },
    { id: 'P03', cat: '1', nome: 'Ibuprofeno 600mg', desc: 'Caixa c/ 20 comprimidos', preco: 14.90, receita: false, estoque: true },
    { id: 'P04', cat: '2', nome: 'Amoxicilina 500mg', desc: 'Caixa c/ 15 cápsulas', preco: 22.00, receita: true, estoque: true },
    { id: 'P05', cat: '2', nome: 'Azitromicina 500mg', desc: 'Caixa c/ 3 comprimidos', preco: 18.50, receita: true, estoque: false },
    { id: 'P06', cat: '3', nome: 'Vitamina C 1g', desc: 'Frasco c/ 30 efervescentes', preco: 24.90, receita: false, estoque: true },
    { id: 'P07', cat: '3', nome: 'Vitamina D3 2000UI', desc: 'Frasco c/ 60 cápsulas', preco: 39.90, receita: false, estoque: true },
    { id: 'P08', cat: '3', nome: 'Ômega 3 1000mg', desc: 'Frasco c/ 60 cápsulas', preco: 34.90, receita: false, estoque: true },
    { id: 'P09', cat: '4', nome: 'Hidratante Corporal', desc: 'Frasco 200ml pele seca', preco: 19.90, receita: false, estoque: true },
    { id: 'P10', cat: '4', nome: 'Protetor Solar FPS50', desc: 'Bisnaga 60g facial', preco: 42.00, receita: false, estoque: true },
    { id: 'P11', cat: '5', nome: 'Enalapril 10mg', desc: 'Caixa c/ 30 comprimidos', preco: 12.00, receita: true, estoque: true },
    { id: 'P12', cat: '5', nome: 'Losartana 50mg', desc: 'Caixa c/ 30 comprimidos', preco: 14.50, receita: true, estoque: true },
    { id: 'P13', cat: '6', nome: 'Omeprazol 20mg', desc: 'Caixa c/ 28 cápsulas', preco: 15.90, receita: false, estoque: true },
    { id: 'P14', cat: '6', nome: 'Buscopan Composto', desc: 'Caixa c/ 20 drágeas', preco: 21.00, receita: false, estoque: true }
  ]
};

// =============================================
// FUNÇÕES DE MENSAGEM (usadas sem IA)
// =============================================
function menuBoasVindas() {
  return `🏪 *Bem-vindo à FarmaBot!* 👋\n\nOlá! Sou seu assistente virtual. Estou aqui para te ajudar a encontrar medicamentos e produtos com rapidez e segurança.\n\n✅ *Atendimento 24h • 7 dias por semana*\n\nPara começarmos, qual é o seu nome?`;
}

function menuPrincipal(nome) {
  return `Olá, *${nome}*! 😊 O que você precisa hoje?\n\n1️⃣  💊  Ver produtos e catálogo\n2️⃣  📦  Acompanhar meu pedido\n3️⃣  🛒  Ver meu carrinho\n4️⃣  👤  Falar com atendente\n\n_Digite o número da opção desejada._`;
}

function menuCategorias() {
  let txt = `💊 *Nosso Catálogo* — Escolha uma categoria:\n\n`;
  CATALOGO.categorias.forEach(c => {
    txt += `*${c.id}* ${c.emoji}  ${c.nome}\n`;
  });
  txt += `\n*0*  ← Voltar ao menu`;
  return txt;
}

function listaProdutos(catId) {
  const cat = CATALOGO.categorias.find(c => c.id === catId);
  const prods = CATALOGO.produtos.filter(p => p.cat === catId);
  let txt = `${cat.emoji} *${cat.nome}*\n${'─'.repeat(28)}\n\n`;
  prods.forEach((p, i) => {
    const st = p.estoque ? '✅ em estoque' : '❌ sem estoque';
    const rc = p.receita ? ' │ 📋 receita' : '';
    txt += `*${i+1}.* ${p.nome}\n    ${p.desc}\n    💰 R$ ${p.preco.toFixed(2)}  │  ${st}${rc}\n\n`;
  });
  txt += `*0*  ← Voltar às categorias\n\nℹ️ *Dica:* Adicione *?* após o número para saber mais sobre o produto _(ex: *1?* para detalhes)_\n\n_📋 = Exige receita médica_`;
  return txt;
}

function resumoCarrinho(cartItems) {
  if (!cartItems || cartItems.length === 0) {
    return `🛒 Seu carrinho está *vazio*.\n\nDigite *1* para ver nosso catálogo!`;
  }
  let txt = `🛒 *Seu Carrinho*\n${'─'.repeat(28)}\n\n`;
  let total = 0;
  cartItems.forEach((item, i) => {
    txt += `${i+1}. *${item.nome}*\n   ${item.qtd}x R$ ${item.preco.toFixed(2)} = R$ ${item.subtotal.toFixed(2)}\n`;
    total += item.subtotal;
  });
  const frete = 5.90;
  txt += `\n${'─'.repeat(28)}\n🚚 Frete: R$ ${frete.toFixed(2)}\n💵 *Total: R$ ${(total + frete).toFixed(2)}*\n\n*1*  ✅ Finalizar pedido\n*2*  🛍️ Continuar comprando\n*3*  🗑️ Esvaziar carrinho`;
  return txt;
}

// =============================================
// MÁQUINA DE ESTADOS
// =============================================

switch (session.step) {

  // ---------- INÍCIO ----------
  case 'INICIO':
    session.step = 'AGUARDANDO_NOME';
    useAI = false;
    responseText = menuBoasVindas();
    break;

  // ---------- AGUARDANDO NOME ----------
  case 'AGUARDANDO_NOME': {
    const nome = msgOriginal.trim();
    if (nome.length < 2) {
      responseText = `❌ Por favor, digite seu *nome completo* para continuar.`;
    } else {
      session.customerName = nome;
      session.step = 'MENU_PRINCIPAL';
      useAI = true;
      aiContext = `O cliente acabou de se identificar como "${nome}" e está acessando uma farmácia virtual via WhatsApp pela primeira vez. Dê as boas vindas de forma calorosa pelo nome, mencione brevemente que pode ajudar com medicamentos e produtos, e apresente as 4 opções do menu: 1-Ver produtos, 2-Acompanhar pedido, 3-Ver carrinho, 4-Falar com atendente. Use emojis e formatação WhatsApp (*negrito*). Seja simpático mas objetivo.`;
    }
    break;
  }

  // ---------- MENU PRINCIPAL ----------
  case 'MENU_PRINCIPAL':
    if (msg === '1' || msg.includes('produto') || msg.includes('catálogo') || msg.includes('catalogo') || msg.includes('comprar')) {
      session.step = 'ESCOLHENDO_CATEGORIA';
      responseText = menuCategorias();
    } else if (msg === '2' || msg.includes('pedido') || msg.includes('acompanhar') || msg.includes('rastrear')) {
      session.step = 'CONSULTA_PEDIDO';
      responseText = `📦 *Consultar Pedido*\n\nInforme o *número do seu pedido*:\n_(Exemplo: PED-1234567890)_`;
    } else if (msg === '3' || msg.includes('carrinho')) {
      session.step = 'REVISANDO_CARRINHO';
      responseText = resumoCarrinho(session.cartItems);
    } else if (msg === '4') {
      // Vai para transferência — tratado no roteador, mas por segurança:
      session.step = 'AGUARDANDO_HUMANO';
      responseText = `👤 Transferindo para atendente...`;
    } else {
      // Mensagem livre → IA interpreta
      useAI = true;
      aiContext = `Você é atendente virtual de uma farmácia. O cliente "${session.customerName || 'Cliente'}" enviou: "${msgOriginal}". Responda de forma simpática e redirecione para uma dessas opções do menu: 1-Ver produtos, 2-Acompanhar pedido, 3-Ver carrinho, 4-Falar com atendente. Use emojis e *negrito* do WhatsApp.`;
    }
    break;

  // ---------- ESCOLHENDO CATEGORIA ----------
  case 'ESCOLHENDO_CATEGORIA':
    if (msg === '0' || msg === 'voltar') {
      session.step = 'MENU_PRINCIPAL';
      responseText = menuPrincipal(session.customerName);
    } else {
      const cat = CATALOGO.categorias.find(c => c.id === msg.trim());
      if (cat) {
        session.step = 'ESCOLHENDO_PRODUTO';
        session.currentCategory = cat.id;
        responseText = listaProdutos(cat.id);
      } else {
        useAI = true;
        aiContext = `Atendente de farmácia. O cliente digitou "${msgOriginal}" quando deveria escolher uma categoria de 1 a 6 ou 0 para voltar. Peça que escolha um número válido da lista de categorias. Seja breve e simpático. Use emojis.`;
      }
    }
    break;

  // ---------- ESCOLHENDO PRODUTO ----------
  case 'ESCOLHENDO_PRODUTO': {
    if (msg === '0' || msg === 'voltar') {
      session.step = 'ESCOLHENDO_CATEGORIA';
      responseText = menuCategorias();
    } else {
      const catProds = CATALOGO.produtos.filter(p => p.cat === session.currentCategory);

      // Detecta "número?" para solicitar detalhes (ex: "1?")
      const detailMatch = msg.trim().match(/^(\d+)\?$/);
      const numStr = detailMatch ? detailMatch[1] : msg.trim();
      const wantsDetails = !!detailMatch;

      // Detecta perguntas livres sobre produtos
      const wantsInfo = !detailMatch && (
        msg.includes('explique') || msg.includes('explicar') ||
        msg.includes('detalhe') || msg.includes('saber mais') ||
        msg.includes('fale sobre') || msg.includes('o que é') ||
        msg.includes('o que e') || msg.includes('quero saber') ||
        msg.includes('me conta') || msg.includes('informação') ||
        msg.includes('informacao') || msg.includes('para que serve') ||
        msg.includes('pra que serve')
      );

      if (wantsInfo) {
        // Tenta identificar produto pelo nome na mensagem
        const matchedProd = catProds.find(p =>
          msg.includes(p.nome.toLowerCase().split(' ')[0]) ||
          msg.includes(p.nome.toLowerCase())
        );
        if (matchedProd) {
          session.step = 'DETALHES_PRODUTO';
          session.selectedProduct = matchedProd.id;
          useAI = true;
          aiContext = `Você é um farmacêutico virtual especialista. O cliente quer saber mais sobre "${matchedProd.nome}" (${matchedProd.desc}, R$ ${matchedProd.preco.toFixed(2)}). Explique de forma clara e didática: para que serve, como age no organismo, principais indicações, posologia habitual, possíveis contraindicações e efeitos colaterais mais comuns${matchedProd.receita ? ', e por que exige receita médica' : ''}. Use emojis e *negrito* do WhatsApp para organizar. Ao final, diga que pode responder mais dúvidas e ofereça: *SIM* para adicionar ao carrinho ou *0* para voltar.`;
        } else {
          useAI = true;
          aiContext = `Atendente de farmácia. O cliente perguntou "${msgOriginal}" enquanto escolhia um produto. Diga que pode explicar sobre qualquer produto da lista — basta digitar o número seguido de *?* (ex: *1?*) para receber informações detalhadas. Seja simpático.`;
        }
        break;
      }

      const idx = parseInt(numStr) - 1;
      const prod = catProds[idx];

      if (prod && wantsDetails) {
        // Usuário quer saber mais antes de comprar
        session.step = 'DETALHES_PRODUTO';
        session.selectedProduct = prod.id;
        useAI = true;
        aiContext = `Você é um farmacêutico virtual especialista. O cliente quer saber mais sobre "${prod.nome}" (${prod.desc}, R$ ${prod.preco.toFixed(2)}). Explique de forma clara e acessível: para que serve, como age no organismo, indicações, posologia habitual, contraindicações e efeitos colaterais mais comuns${prod.receita ? ', por que exige receita médica e cuidados especiais' : ''}. Seja didático, use emojis e *negrito* do WhatsApp. Ao final, informe que pode tirar mais dúvidas e ofereça: *SIM* para adicionar ao carrinho${!prod.estoque ? ' (obs: sem estoque no momento)' : ''} ou *0* para voltar à lista.`;
      } else if (prod) {
        if (!prod.estoque) {
          useAI = true;
          aiContext = `Atendente de farmácia. O produto "${prod.nome}" está sem estoque no momento. Informe isso ao cliente de forma empática, sugira verificar outros produtos da categoria ou voltar depois. Seja simpático. Use emojis do WhatsApp.`;
        } else if (prod.receita) {
          session.step = 'AGUARDANDO_RECEITA';
          session.pendingProduct = prod.id;
          useAI = true;
          aiContext = `Atendente de farmácia. O cliente quer comprar "${prod.nome}" que exige receita médica. Explique que é um medicamento controlado, que é necessário enviar foto da receita médica válida para continuar, e peça para enviar a imagem. Seja profissional e acolhedor. Use emojis do WhatsApp e *negrito*.`;
        } else {
          session.step = 'CONFIRMANDO_QUANTIDADE';
          session.selectedProduct = prod.id;
          useAI = true;
          aiContext = `Atendente de farmácia. O cliente escolheu o produto:\n- Nome: ${prod.nome}\n- Descrição: ${prod.desc}\n- Preço: R$ ${prod.preco.toFixed(2)}\n\nApresente o produto de forma atraente com suas características e pergunte quantas unidades o cliente deseja. Use emojis do WhatsApp e *negrito* para destacar o nome e o preço.`;
        }
      } else {
        useAI = true;
        aiContext = `Atendente de farmácia. O cliente digitou "${msgOriginal}" e não reconheci um produto válido. Peça que escolha um número da lista, adicione *?* para saber mais sobre um produto (ex: *1?*), ou *0* para voltar às categorias. Seja breve.`;
      }
    }
    break;
  }

  // ---------- DETALHES DO PRODUTO ----------
  case 'DETALHES_PRODUTO': {
    const prodD = CATALOGO.produtos.find(p => p.id === session.selectedProduct);
    if (msg === '0' || msg === 'voltar') {
      session.step = 'ESCOLHENDO_PRODUTO';
      responseText = listaProdutos(session.currentCategory);
    } else if (msg === 'sim' || msg === '1' || msg.includes('adicionar') || msg.includes('comprar') || msg.includes('quero') || msg.includes('carrinho') || msg.includes('sim quero')) {
      if (!prodD.estoque) {
        useAI = true;
        aiContext = `Atendente de farmácia. O produto "${prodD.nome}" infelizmente está sem estoque. Informe de forma simpática e sugira outros produtos da categoria. Use emojis.`;
      } else if (prodD.receita) {
        session.step = 'AGUARDANDO_RECEITA';
        session.pendingProduct = prodD.id;
        session.selectedProduct = null;
        useAI = true;
        aiContext = `Atendente de farmácia. O cliente decidiu comprar "${prodD.nome}" que exige receita médica. Explique que é necessário enviar foto da receita para continuar. Seja profissional e acolhedor. Use emojis e *negrito*.`;
      } else {
        session.step = 'CONFIRMANDO_QUANTIDADE';
        useAI = true;
        aiContext = `Atendente de farmácia. O cliente decidiu comprar "${prodD.nome}" (R$ ${prodD.preco.toFixed(2)}) após ver os detalhes. Confirme a ótima escolha e pergunte quantas unidades deseja. Use emojis e *negrito*.`;
      }
    } else {
      // Pergunta livre sobre o produto — a IA responde como farmacêutico especialista
      useAI = true;
      aiContext = `Você é um farmacêutico virtual especialista. O cliente está perguntando sobre o medicamento/produto "${prodD.nome}": "${msgOriginal}". Responda de forma precisa, clara e acessível para leigos. Use emojis e *negrito* do WhatsApp para organizar a resposta. Ao final, lembre que pode digitar *SIM* para adicionar ao carrinho ou *0* para voltar à lista.`;
    }
    break;
  }

  // ---------- AGUARDANDO RECEITA ----------
  case 'AGUARDANDO_RECEITA':
    if (data.messageType === 'image' || data.messageType === 'document') {
      const prodR = CATALOGO.produtos.find(p => p.id === session.pendingProduct);
      session.step = 'CONFIRMANDO_QUANTIDADE';
      session.selectedProduct = session.pendingProduct;
      session.pendingProduct = null;
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente enviou a receita médica com sucesso. Confirme o recebimento, informe que o produto "${prodR.nome}" (R$ ${prodR.preco.toFixed(2)}) está disponível e pergunte a quantidade desejada. Seja simpático e use emojis.`;
    } else {
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente ainda precisa enviar a *foto da receita médica* para o produto controlado que deseja. Lembre-o de forma gentil que precisa enviar a imagem da receita (foto ou PDF). Diga que sem isso não é possível processar a compra. Use emojis.`;
    }
    break;

  // ---------- CONFIRMANDO QUANTIDADE ----------
  case 'CONFIRMANDO_QUANTIDADE': {
    const qtd = parseInt(msg.trim());
    const prodQ = CATALOGO.produtos.find(p => p.id === session.selectedProduct);
    if (!isNaN(qtd) && qtd >= 1 && qtd <= 99) {
      const item = {
        productId: prodQ.id,
        nome: prodQ.nome,
        qtd,
        preco: prodQ.preco,
        subtotal: qtd * prodQ.preco
      };
      if (!session.cartItems) session.cartItems = [];
      session.cartItems.push(item);
      session.selectedProduct = null;
      session.step = 'POS_ADICIONAR';
      const totalCarrinho = session.cartItems.reduce((a, i) => a + i.subtotal, 0);
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente acabou de adicionar ao carrinho:\n- Produto: ${prodQ.nome}\n- Quantidade: ${qtd}\n- Subtotal: R$ ${item.subtotal.toFixed(2)}\n- Total atual do carrinho: R$ ${totalCarrinho.toFixed(2)}\n\nConfirme o item adicionado e apresente as opções: 1-Continuar comprando, 2-Ver carrinho e finalizar, 3-Esvaziar carrinho. Seja animado e use emojis do WhatsApp.`;
    } else {
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente digitou "${msgOriginal}" quando deveria informar a quantidade (número entre 1 e 99). Peça de forma simpática que informe um número válido de unidades.`;
    }
    break;
  }

  // ---------- PÓS ADICIONAR ----------
  case 'POS_ADICIONAR':
    if (msg === '1' || msg.includes('continuar') || msg.includes('mais')) {
      session.step = 'ESCOLHENDO_CATEGORIA';
      responseText = menuCategorias();
    } else if (msg === '2' || msg.includes('carrinho') || msg.includes('finalizar')) {
      session.step = 'REVISANDO_CARRINHO';
      responseText = resumoCarrinho(session.cartItems);
    } else if (msg === '3' || msg.includes('esvaziar') || msg.includes('limpar')) {
      session.cartItems = [];
      session.step = 'MENU_PRINCIPAL';
      useAI = true;
      aiContext = `Atendente de farmácia. O carrinho do cliente "${session.customerName}" foi esvaziado. Confirme isso de forma simpática e apresente o menu principal com as opções 1-Ver produtos, 2-Pedidos, 3-Carrinho, 4-Atendente. Use emojis.`;
    } else {
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente adicionou um item ao carrinho e deve escolher: 1-Continuar comprando, 2-Ver carrinho, 3-Esvaziar carrinho. Ele digitou "${msgOriginal}". Peça que escolha uma das opções acima. Seja simpático.`;
    }
    break;

  // ---------- REVISANDO CARRINHO ----------
  case 'REVISANDO_CARRINHO':
    if (msg === '1' || msg.includes('finalizar') || msg.includes('comprar')) {
      session.step = 'AGUARDANDO_ENDERECO';
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente vai finalizar o pedido. Peça o *endereço completo de entrega* (Rua, número, bairro, cidade) de forma simpática. Mencione que a entrega é feita em até 4 horas. Use emojis.`;
    } else if (msg === '2' || msg.includes('continuar')) {
      session.step = 'ESCOLHENDO_CATEGORIA';
      responseText = menuCategorias();
    } else if (msg === '3' || msg.includes('esvaziar')) {
      session.cartItems = [];
      session.step = 'MENU_PRINCIPAL';
      responseText = menuPrincipal(session.customerName);
    } else {
      responseText = resumoCarrinho(session.cartItems);
    }
    break;

  // ---------- AGUARDANDO ENDEREÇO ----------
  case 'AGUARDANDO_ENDERECO':
    if (msgOriginal.trim().length < 10) {
      useAI = true;
      aiContext = `Atendente de farmácia. O endereço informado pelo cliente parece incompleto ("${msgOriginal}"). Peça gentilmente que informe o endereço completo: Rua, número, bairro e cidade.`;
    } else {
      session.deliveryAddress = msgOriginal.trim();
      session.step = 'ESCOLHENDO_PAGAMENTO';
      const tot = session.cartItems.reduce((a, i) => a + i.subtotal, 0);
      const totFinal = tot + 5.90;
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente informou o endereço de entrega: "${msgOriginal}". Confirme o endereço e apresente as formas de pagamento disponíveis:\n- 1: PIX (com 5% de desconto)\n- 2: Cartão de Crédito\n- 3: Cartão de Débito\n- 4: Dinheiro na entrega\n\nO total do pedido (com frete R$ 5,90) é R$ ${totFinal.toFixed(2)}. Destaque que o PIX dá desconto. Use emojis e *negrito* do WhatsApp.`;
    }
    break;

  // ---------- ESCOLHENDO PAGAMENTO ----------
  case 'ESCOLHENDO_PAGAMENTO': {
    const payMap = { '1': 'PIX', '2': 'Cartão de Crédito', '3': 'Cartão de Débito', '4': 'Dinheiro na entrega' };
    const pay = payMap[msg.trim()];
    if (!pay) {
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente digitou "${msgOriginal}" quando deveria escolher a forma de pagamento: 1-PIX, 2-Crédito, 3-Débito, 4-Dinheiro. Peça gentilmente que escolha uma opção válida.`;
    } else {
      session.paymentMethod = pay;
      const subtotal = session.cartItems.reduce((a, i) => a + i.subtotal, 0);
      const frete = 5.90;
      const desconto = pay === 'PIX' ? subtotal * 0.05 : 0;
      const totalFinal = subtotal + frete - desconto;
      session.orderTotal = totalFinal;
      session.step = 'CONFIRMANDO_PEDIDO';
      const listaItens = session.cartItems.map(i => `• ${i.nome} x${i.qtd} = R$ ${i.subtotal.toFixed(2)}`).join('\n');
      useAI = true;
      aiContext = `Atendente de farmácia. Apresente o resumo final do pedido para confirmação:\n\nCliente: ${session.customerName}\nEndereço: ${session.deliveryAddress}\nPagamento: ${pay}\n\nItens:\n${listaItens}\n\nFrete: R$ ${frete.toFixed(2)}${desconto > 0 ? `\nDesconto PIX 5%: -R$ ${desconto.toFixed(2)}` : ''}\nTotal final: R$ ${totalFinal.toFixed(2)}\n\nPeça confirmação com as opções: *1* para CONFIRMAR ou *2* para CANCELAR. Use emojis e *negrito* do WhatsApp. Seja entusiasmado.`;
    }
    break;
  }

  // ---------- CONFIRMANDO PEDIDO ----------
  case 'CONFIRMANDO_PEDIDO':
    if (msg === '1' || msg.includes('sim') || msg.includes('confirmar') || msg.includes('confirmo')) {
      const orderId = 'PED-' + Date.now();
      session.orderId = orderId;
      session.orderStatus = 'CONFIRMADO';
      session.orderConfirmedAt = new Date().toISOString();
      session.step = 'PEDIDO_FINALIZADO';
      const pixInfo = session.paymentMethod === 'PIX'
        ? `\n\n💠 *Chave PIX para pagamento:*\nfarmacia@exemplo.com\nValor: R$ ${session.orderTotal.toFixed(2)}\n\n_Após confirmar o PIX, seu pedido entra em preparo automaticamente._`
        : '';
      useAI = true;
      aiContext = `Atendente de farmácia. O pedido foi confirmado com sucesso! Número do pedido: ${orderId}. Forma de pagamento: ${session.paymentMethod}.${pixInfo}\n\nComemore com o cliente, confirme o número do pedido, informe que a entrega será em até 4 horas e que ele receberá atualizações por aqui. Seja caloroso e agradecido. Use muitos emojis festivos e *negrito*.`;
    } else if (msg === '2' || msg.includes('não') || msg.includes('nao') || msg.includes('cancelar')) {
      session.step = 'MENU_PRINCIPAL';
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente cancelou a confirmação do pedido. Informe que o pedido foi cancelado, que os itens ainda estão no carrinho caso queira alterar algo, e apresente o menu principal: 1-Ver produtos, 2-Pedidos, 3-Carrinho, 4-Atendente. Seja compreensivo.`;
    } else {
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente precisa responder *1* para confirmar o pedido ou *2* para cancelar. Ele digitou "${msgOriginal}". Peça gentilmente que responda com 1 ou 2.`;
    }
    break;

  // ---------- PEDIDO FINALIZADO ----------
  case 'PEDIDO_FINALIZADO':
    useAI = true;
    aiContext = `Atendente de farmácia. O cliente já tem um pedido confirmado (${session.orderId}). Ele enviou: "${msgOriginal}". Informe o status do pedido e pergunte se pode ajudar com mais alguma coisa. Ofereça o menu principal se necessário. Seja simpático.`;
    break;

  // ---------- CONSULTA PEDIDO ----------
  case 'CONSULTA_PEDIDO': {
    const pid = msgOriginal.trim().toUpperCase();
    if (pid.startsWith('PED-')) {
      session.step = 'MENU_PRINCIPAL';
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente consultou o pedido ${pid}. Informe que o pedido está *Em Preparo* e a previsão de entrega é hoje até as 18h. Pergunte se pode ajudar com mais alguma coisa. Use emojis.`;
    } else {
      useAI = true;
      aiContext = `Atendente de farmácia. O cliente está consultando um pedido mas digitou "${msgOriginal}" que não parece ser um número de pedido válido (formato: PED-XXXXXXXXXX). Peça gentilmente que informe o número correto do pedido.`;
    }
    break;
  }

  default:
    session.step = 'MENU_PRINCIPAL';
    responseText = menuPrincipal(session.customerName || 'Cliente');
}

// Salva sessão atualizada
if (!staticData.sessions) staticData.sessions = {};
staticData.sessions[data.phone] = session;

return [{
  json: {
    ...data,
    session,
    responseText,
    useAI,
    aiContext
  }
}];

// Reset da sessão para o menu principal
const staticData = $getWorkflowStaticData('global');
const data = $input.first().json;
if (!staticData.sessions) staticData.sessions = {};

const session = staticData.sessions[data.phone] || {};
const nome = session.customerName || 'Cliente';

const updatedSession = { ...session, step: 'MENU_PRINCIPAL' };
staticData.sessions[data.phone] = updatedSession;

return [{
  json: {
    ...data,
    session: updatedSession,
    responseText: '',
    useAI: true,
    aiContext: `Atendente de farmácia virtual. O cliente "${nome}" voltou ao menu principal. Dê as boas vindas de volta e apresente as opções: 1-Ver produtos, 2-Acompanhar pedido, 3-Ver carrinho, 4-Falar com atendente. Use emojis e seja simpático.`
  }
}];

// Prepara transferência para atendente humano
const staticData = $getWorkflowStaticData('global');
const data = $input.first().json;
if (!staticData.sessions) staticData.sessions = {};

const session = staticData.sessions[data.phone] || {};
const updatedSession = {
  ...session,
  step: 'AGUARDANDO_HUMANO',
  transferredAt: new Date().toISOString()
};
staticData.sessions[data.phone] = updatedSession;

const nome = session.customerName || 'Cliente';
const cartValue = (session.cartItems || []).reduce((a, i) => a + i.subtotal, 0);

const alertaInterno = `🔔 *ATENDIMENTO HUMANO SOLICITADO*\n\n👤 Cliente: ${nome}\n📱 WhatsApp: ${data.phone}\n⏰ Horário: ${new Date().toLocaleString('pt-BR')}\n💬 Mensagem: "${data.messageText}"\n🛒 Carrinho: R$ ${cartValue.toFixed(2)} (${(session.cartItems||[]).length} item(s))\n\n_Acesse o painel para ver o histórico._`;

return [{
  json: {
    ...data,
    session: updatedSession,
    responseText: '',
    useAI: true,
    aiContext: `Atendente virtual de farmácia. O cliente "${nome}" solicitou atendimento humano. Informe que a solicitação foi registrada, que um atendente humano vai responder em até 5 minutos, e peça que aguarde. Seja acolhedor e tranquilizador. Use emojis.`,
    alertaInterno
  }
}];

// Cliente já está na fila, apenas mantém
const data = $input.first().json;
return [{
  json: {
    ...data,
    responseText: '',
    useAI: true,
    aiContext: `Atendente virtual de farmácia. O cliente já está na fila aguardando atendimento humano. Ele enviou: "${data.messageText}". Informe que um atendente humano vai responder em breve, que a mensagem foi registrada. Se ele quiser voltar ao atendimento automático pode digitar *menu*. Seja breve e tranquilizador.`
  }
}];

// Extrai o texto da resposta da Groq (formato compatível com OpenAI)
const aiResponse = $input.first().json;
const text = aiResponse.choices?.[0]?.message?.content || 'Desculpe, tive um problema. Tente novamente.';

// Pega dados originais do fluxo (usa isExecuted para evitar erro quando nó não rodou)
const flowData = ($('Lógica do Bot').isExecuted ? $('Lógica do Bot').first().json : null)
  || ($('Reset Menu').isExecuted ? $('Reset Menu').first().json : null)
  || ($('Transferir para Humano').isExecuted ? $('Transferir para Humano').first().json : null)
  || ($('Em Fila Humano').isExecuted ? $('Em Fila Humano').first().json : null)
  || {};

return [{
  json: {
    ...flowData,
    finalMessage: text
  }
}];

// Passa resposta direta (sem IA)
const data = $input.first().json;
return [{
  json: {
    ...data,
    finalMessage: data.responseText
  }
}];

// Coleta métricas em Static Data para o futuro WebApp
const staticData = $getWorkflowStaticData('global');
if (!staticData.metrics) {
  staticData.metrics = {
    totalMensagens: 0,
    totalSessoes: 0,
    totalPedidos: 0,
    receitaTotal: 0,
    transferenciasHumano: 0,
    ultimosEventos: [],
    estatisticasDiarias: {}
  };
}

// O input vem da resposta HTTP do Z-API (sem session/phone).
// Recupera dados do fluxo e sessão atualizada no Static Data.
const flowData = ($('Busca Sessão (Static Data)').isExecuted ? $('Busca Sessão (Static Data)').first().json : null)
  || ($('Normaliza Mensagem').isExecuted ? $('Normaliza Mensagem').first().json : null)
  || {};

const phone = flowData.phone;
const session = (staticData.sessions && phone && staticData.sessions[phone])
  ? staticData.sessions[phone]
  : (flowData.session || {});

const data = { ...flowData, session };
const timestamp = new Date().toISOString();
const hoje = timestamp.split('T')[0];

// Inicializa dia
if (!staticData.metrics.estatisticasDiarias[hoje]) {
  staticData.metrics.estatisticasDiarias[hoje] = {
    mensagens: 0, sessoes: 0, pedidos: 0, receita: 0, transferencias: 0
  };
}

staticData.metrics.totalMensagens++;
staticData.metrics.estatisticasDiarias[hoje].mensagens++;

if (data.isNewSession) {
  staticData.metrics.totalSessoes++;
  staticData.metrics.estatisticasDiarias[hoje].sessoes++;
}

const pedidoJaRegistrado = session.orderId
  && staticData.metrics.ultimosEventos.some(e => e.orderId === session.orderId && e.event === 'PEDIDO_CRIADO');

const temPedidoParaRegistrar = session.orderId && !pedidoJaRegistrado;

if (temPedidoParaRegistrar) {
  staticData.metrics.totalPedidos++;
  staticData.metrics.receitaTotal += session.orderTotal || 0;
  staticData.metrics.estatisticasDiarias[hoje].pedidos++;
  staticData.metrics.estatisticasDiarias[hoje].receita += session.orderTotal || 0;
}

if (session.step === 'AGUARDANDO_HUMANO') {
  staticData.metrics.transferenciasHumano++;
  staticData.metrics.estatisticasDiarias[hoje].transferencias++;
}

// Evento para histórico (sem null — dashboard rejeita campos nulos)
let eventType = 'MENSAGEM';
if (session.step === 'AGUARDANDO_HUMANO') {
  eventType = 'TRANSFERENCIA_HUMANO';
} else if (temPedidoParaRegistrar) {
  eventType = 'PEDIDO_CRIADO';
}

const evt = {
  id: `EVT-${Date.now()}`,
  timestamp,
  phone: data.phone,
  step: temPedidoParaRegistrar ? 'PEDIDO_FINALIZADO' : session.step,
  event: eventType
};
if (session.customerName) evt.customerName = session.customerName;
if (session.orderId) evt.orderId = session.orderId;
if (session.orderTotal) evt.orderTotal = session.orderTotal;
if (session.paymentMethod) evt.paymentMethod = session.paymentMethod;
if (session.deliveryAddress) evt.deliveryAddress = session.deliveryAddress;
if (eventType === 'PEDIDO_CRIADO' && session.cartItems?.length) {
  evt.items = session.cartItems.map(i => ({
    name: i.nome || i.name,
    quantity: i.qty || i.quantity || 1,
    price: i.preco || i.price,
    subtotal: i.subtotal
  }));
}
staticData.metrics.ultimosEventos.unshift(evt);

// Mantém apenas últimos 200 eventos
if (staticData.metrics.ultimosEventos.length > 200) {
  staticData.metrics.ultimosEventos = staticData.metrics.ultimosEventos.slice(0, 200);
}

// Calcula taxa de conversão
const taxa = staticData.metrics.totalSessoes > 0
  ? ((staticData.metrics.totalPedidos / staticData.metrics.totalSessoes) * 100).toFixed(1)
  : '0.0';

const metricsPayload = {
  ...staticData.metrics,
  taxaConversao: taxa,
  ticketMedio: staticData.metrics.totalPedidos > 0
    ? (staticData.metrics.receitaTotal / staticData.metrics.totalPedidos).toFixed(2)
    : '0.00',
  geradoEm: timestamp
};

return [{
  json: {
    ...data,
    metricsPayload,
    metricsJson: JSON.stringify(metricsPayload, null, 2)
  }
}];

// Métricas salvas em Static Data (writeBinaryFile removido em versões novas do n8n)
const staticData = $getWorkflowStaticData('global');
staticData.lastMetricsJson = $input.first().json.metricsJson;
return $input.all();
